def process_complexity_matrix(matrix, scale_factor):
    results = []
    for i in range(len(matrix)):
        row = matrix[i]
        row_results = []
        for j in range(len(row)):
            val = row[j] * scale_factor
            row_results.append(val)
        results.append(row_results)
    return results

