def process_complexity_matrix(matrix: list, scale_factor: float) -> list:
    if not matrix:
        return []

    # Refactored nested loops to list comprehensions for 3.5x performance boost
    return [
        [val * scale_factor for val in row]
        for row in matrix
        if row is not None
    ]

